import{_ as e,o as r,c as i,ah as t}from"./chunks/framework.CkJUk41Q.js";const _=JSON.parse('{"title":"健壮性","description":"","frontmatter":{"title":"健壮性","order":30},"headers":[],"relativePath":"server/distribute/micro/reliability/index.md","filePath":"server/distribute/micro/reliability/index.md"}'),l={name:"server/distribute/micro/reliability/index.md"};function n(d,a,s,o,h,c){return r(),i("div",null,[...a[0]||(a[0]=[t('<h1 id="微服务健壮性" tabindex="-1">微服务健壮性 <a class="header-anchor" href="#微服务健壮性" aria-label="Permalink to “微服务健壮性”">​</a></h1><p>微服务架构下，服务间的依赖关系复杂，单个服务的故障可能级联扩散，导致整个系统雪崩。健壮性是服务在异常情况下维持核心功能的能力，包括容错、隔离、恢复等机制。</p><h2 id="服务雪崩" tabindex="-1">服务雪崩 <a class="header-anchor" href="#服务雪崩" aria-label="Permalink to “服务雪崩”">​</a></h2><p>服务雪崩是微服务架构中最危险的现象。服务 A 调用服务 B，服务 B 响应慢或故障，服务 A 的线程池被占满，服务 A 也无法响应，故障向上扩散，最终整个系统不可用。</p><p>雪崩的成因：服务故障导致响应变慢、客户端不断重试、线程池耗尽、连接池耗尽、资源耗尽。</p><p>雪崩的传播：服务间调用链形成依赖图，故障沿着调用链向上传播，最终影响所有依赖链上的服务。</p><h2 id="健壮性的核心机制" tabindex="-1">健壮性的核心机制 <a class="header-anchor" href="#健壮性的核心机制" aria-label="Permalink to “健壮性的核心机制”">​</a></h2><h3 id="容错" tabindex="-1">容错 <a class="header-anchor" href="#容错" aria-label="Permalink to “容错”">​</a></h3><p>假设故障必然发生，设计容错机制。超时机制（避免无限等待）、重试机制（短暂故障自动恢复）、熔断机制（快速失败）、降级机制（返回默认值）。</p><h3 id="隔离" tabindex="-1">隔离 <a class="header-anchor" href="#隔离" aria-label="Permalink to “隔离”">​</a></h3><p>隔离故障范围，避免影响整体。线程池隔离（不同服务使用不同线程池）、信号量隔离（限制并发数）、进程隔离（不同服务部署在不同进程）、机房隔离（跨机房部署）。</p><h3 id="恢复" tabindex="-1">恢复 <a class="header-anchor" href="#恢复" aria-label="Permalink to “恢复”">​</a></h3><p>故障后自动恢复，减少人工干预。健康检查（定期检查服务状态）、故障转移（切换到备用实例）、自动重启（服务崩溃后自动重启）、限流保护（保护恢复中的服务）。</p>',13)])])}const b=e(l,[["render",n]]);export{_ as __pageData,b as default};
